const express = require('express');
const { Pool } = require('pg');

const app = express();
app.use(express.json());

const pool = new Pool({
  user: 'postgres',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432,
});

// CRUD operations for Table1
app.get('/table1', async (req, res) => {
  try {
    const result = await pool.query('SELECT * FROM table1');
    res.json(result.rows);
  } catch (error) {
    res.status(500).send(error.toString());
  }
});

app.post('/table1', async (req, res) => {
  const { name, value } = req.body;
  try {
    await pool.query('INSERT INTO table1 (name, value) VALUES ($1, $2)', [name, value]);
    res.send('Record Added');
  } catch (error) {
    res.status(500).send(error.toString());
  }
});

app.put('/table1/:id', async (req, res) => {
  const { id } = req.params;
  const { name, value } = req.body;
  try {
    await pool.query('UPDATE table1 SET name = $1, value = $2 WHERE id = $3', [name, value, id]);
    res.send('Record Updated');
  } catch (error) {
    res.status(500).send(error.toString());
  }
});

app.delete('/table1/:id', async (req, res) => {
  const { id } = req.params;
  try {
    await pool.query('DELETE FROM table1 WHERE id = $1', [id]);
    res.send('Record Deleted');
  } catch (error) {
    res.status(500).send(error.toString());
  }
});

